select count(*) from
market_tbl where market_status = #{status}

	and market_title like '%'||#{searchKeyword}||'%'


	and market_writer = #{searchKeyword}

select market_no, market_title, to_char(market_date, 'yyyy-mm-dd HH24:mi:ss') as market_date, market_writer, view_count, sell_addr, sell_price, ( select market_file_path from ( select mf.market_file_path from market_file_tbl mf where mf.market_no = market_tbl.market_no order by mf.market_file_no asc ) where rownum = 1 ) as marketThumb from market_tbl join member_tbl on (market_writer = member_id) where market_status = #{status}
and market_title like '%'||#{searchKeyword}||'%'
and market_writer = #{searchKeyword}
order by market_no desc order by market_no asc order by view_count desc
order by sell_price desc
offset #{page}*#{size} rows fetch next #{size} rows only

